function knightProbability(n, k, row, col) {
  const moves = [
    [-2, -1], [-2, 1], [-1, 2], [1, 2],
    [2, 1], [2, -1], [1, -2], [-1, -2]
  ];

  const prev = Array.from({ length: n }, () => Array(n).fill(0));
  prev[row][col] = 1;

  for (let step = 0; step < k; step += 1) {
    const cur = Array.from({ length: n }, () => Array(n).fill(0));
    for (let r = 0; r < n; r += 1) {
      for (let c = 0; c < n; c += 1) {
        if (prev[r][c] === 0) continue;
        const share = prev[r][c] / 8;
        for (const [dr, dc] of moves) {
          const nr = r + dr;
          const nc = c + dc;
          if (nr >= 0 && nr < n && nc >= 0 && nc < n) {
            cur[nr][nc] += share;
          }
        }
      }
    }
    for (let r = 0; r < n; r += 1) {
      for (let c = 0; c < n; c += 1) {
        prev[r][c] = cur[r][c];
      }
    }
  }

  let total = 0;
  for (let r = 0; r < n; r += 1) {
    for (let c = 0; c < n; c += 1) {
      total += prev[r][c];
    }
  }
  return total;
}

double KnightProbability(int n, int k, int row, int col)
{
    int[][] dirs = new int[][] {
        new[] { 1, 2 }, new[] { 2, 1 }, new[] { 2, -1 }, new[] { 1, -2 },
        new[] { -1, -2 }, new[] { -2, -1 }, new[] { -2, 1 }, new[] { -1, 2 }
    };

    double[,] dp = new double[n, n];
    dp[row, col] = 1.0;

    for (int move = 0; move < k; move++)
    {
        double[,] next = new double[n, n];
        for (int r = 0; r < n; r++)
        {
            for (int c = 0; c < n; c++)
            {
                if (dp[r, c] == 0) continue;
                foreach (var d in dirs)
                {
                    int nr = r + d[0], nc = c + d[1];
                    if (nr >= 0 && nr < n && nc >= 0 && nc < n)
                        next[nr, nc] += dp[r, c] / 8.0;
                }
            }
        }
        dp = next;
    }

    double ans = 0;
    for (int r = 0; r < n; r++)
        for (int c = 0; c < n; c++)
            ans += dp[r, c];

    return ans;
}

